parameters.jsCode:
const heirData = $json;
const skipOutput  = $('Skip Tracer: Per Heir').item.json.output  || '';
const verifOutput = $('Verification Agent: Per Heir').item.json.output || '';

let skipResult = {};
try {
  const m = skipOutput.match(/\{[\s\S]*\}/);
  if (m) skipResult = JSON.parse(m[0]);
} catch (_) {}

let verifResult = {};
try {
  const m = verifOutput.match(/\{[\s\S]*\}/);
  if (m) verifResult = JSON.parse(m[0]);
} catch (_) {}

const verificationResult = verifResult.verification_result || 'unverified_deceased';

const base = {
  name:                heirData.name,
  relationship:        heirData.relationship,
  share_pct:           heirData.share_pct,
  share_fraction:      heirData.share_fraction,
  basis:               heirData.basis,
  is_deceased_cascade: heirData.is_deceased_cascade || false,
  state:               heirData.state,
  county:              heirData.county || '',
  property_id:         heirData.property_id,
  conclusion_id:       heirData.conclusion_id,
  root_decedent:       heirData.root_decedent,
  skipgenie_result:    skipResult,
  verification:        verifResult,
  verification_result: verificationResult
};

if (verificationResult === 'confirmed_alive') {
  return [{ json: {
    ...base,
    category:     'living',
    phones:       skipResult.phones       || [],
    emails:       skipResult.emails       || [],
    best_address: skipResult.best_address || ''
  } }];
}

if (verificationResult === 'conflict') {
  return [{ json: {
    ...base,
    category: 'conflict',
    gap: `CONFLICT for ${heirData.name}: ${verifResult.note || 'SkipGenie and verification layers disagree'}`
  } }];
}

return [{ json: {
  ...base,
  category:  'deceased',
  dod:       verifResult.dod || skipResult.dod || '',
  relatives: skipResult.possible_relatives || []
} }];

const items = $input.all().map(i => i.json);

const living_heirs    = [];
const deceased_queue  = [];
const gaps            = [];
let   credits_used    = 0;

for (const item of items) {
  if (item.category === 'living') {
    living_heirs.push({
      name:              item.name,
      relationship_path: `${item.relationship} of ${item.root_decedent}`,
      share_pct:         item.share_pct,
      share_fraction:    item.share_fraction,
      is_alive:          true,
      estate_path:       `intestate from ${item.root_decedent}`,
      phones:            item.phones        || [],
      emails:            item.emails        || [],
      best_address:      item.best_address  || '',
      contact_status:    'not_contacted',
      verification:      item.verification
    });
  } else if (item.category === 'deceased') {
    deceased_queue.push(item);
  } else if (item.category === 'conflict') {
    gaps.push(item.gap);
  }
  if (item.skipgenie_result && !item.skipgenie_result.no_result) {
    credits_used++;
  }
}

const webhookBody = $('Webhook').first().json.body;

return [{
  json: {
    living_heirs,
    deceased_queue,
    gaps,
    credits_used,
    root_decedent:  webhookBody.deceased_owner,
    property_id:    webhookBody.property_id,
    conclusion_id:  webhookBody.conclusion_id,
    ancestor_names: [webhookBody.deceased_owner, ...deceased_queue.map(d => d.name)]
  }
}];

// Accepts input from either:
// (a) Code: Cascade Deceased Heirs (TRUE path) — already has deceased_in_chain built
// (b) Merge: Pre-Compiler FALSE path — has deceased_queue (empty, no cascade needed)

const living_heirs = $json.living_heirs || [];
const gaps         = $json.gaps         || [];

const deceased_in_chain = ($json.deceased_in_chain !== undefined)
  ? $json.deceased_in_chain
  : ($json.deceased_queue || []).map(d => ({
      name:              d.name,
      relationship_path: `${d.relationship} of ${d.root_decedent}`,
      share_pct:         d.share_pct,
      share_fraction:    d.share_fraction,
      dod:               d.dod || null,
      estate_type:       null,
      cascaded_to:       [],
      evidence:          d.verification || {}
    }));

return [{
  json: {
    living_heirs,
    deceased_in_chain,
    gaps,
    credits_used:  $json.credits_used  || 0,
    root_decedent: $json.root_decedent,
    property_id:   $json.property_id,
    conclusion_id: $json.conclusion_id
  }
}];

