parameters.jsCode:
const output = $input.first().json.output || '';

let compiled;
try {
  const match = output.match(/\{[\s\S]*\}/);
  if (!match) throw new Error('No JSON found in compiler output');
  compiled = JSON.parse(match[0]);
} catch (e) {
  const ctx = $('Code: Build Compiler Input').first().json;
  return [{
    json: {
      error:        true,
      parse_error:  e.message,
      raw_output:   output.substring(0, 500),
      status:       'parse_error',
      property_id:  ctx.property_id,
      conclusion_id: ctx.conclusion_id,
      root_decedent: ctx.root_decedent,
      total_living_heirs: 0,
      living_heirs:  [],
      deceased_in_chain: [],
      gaps:          ['PARSE ERROR in Heir Tree Compiler output'],
      credits_used:  ctx.credits_used || 0
    }
  }];
}

return [{ json: compiled }];

const pg       = $('Postgres: Write heir_traces').first().json;
const compiled = $('Code: Parse Compiler Output').first().json;

return [{
  json: {
    success:            !compiled.error,
    trace_id:           pg.id,
    status:             compiled.status || 'error',
    root_decedent:      compiled.root_decedent,
    total_living_heirs: compiled.total_living_heirs || 0,
    living_heirs:       compiled.living_heirs       || [],
    deceased_in_chain:  compiled.deceased_in_chain  || [],
    gaps:               compiled.gaps               || [],
    credits_used:       compiled.credits_used       || 0,
    message:            compiled.error
      ? `Heir trace failed: ${compiled.parse_error || 'compiler parse error'}`
      : `Heir trace ${compiled.status}. ${compiled.total_living_heirs || 0} living heir(s) found.`
  }
}];

const data = $json;
const webhookBody = $('Webhook').first().json.body;
const currentDepth = webhookBody.cascade_depth || 0;
const WEBHOOK_URL = $vars.HEIR_TRACER_URL || 'http://localhost:5678/webhook/heir-trace/start';
const DEPTH_LIMIT = 4;

const deceased_queue = data.deceased_queue || [];
const living_heirs = [...(data.living_heirs || [])];
const gaps = [...(data.gaps || [])];
const deceased_in_chain = [];

for (const deceased of deceased_queue) {
  if (currentDepth >= DEPTH_LIMIT) {
    gaps.push(`${deceased.name} — cascade depth limit (${DEPTH_LIMIT}). Manual review required.`);
    deceased_in_chain.push({
      name:              deceased.name,
      relationship_path: `${deceased.relationship} of ${data.root_decedent}`,
      share_pct:         deceased.share_pct,
      share_fraction:    deceased.share_fraction,
      dod:               deceased.dod || null,
      estate_type:       null,
      cascaded_to:       [],
      evidence:          deceased.verification || {}
    });
    continue;
  }

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: WEBHOOK_URL,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        deceased_owner:    deceased.name,
        last_known_state:  deceased.state  || webhookBody.last_known_state,
        last_known_county: deceased.county || webhookBody.last_known_county,
        approx_death_year: deceased.dod ? String(deceased.dod).substring(0, 4) : null,
        property_id:       deceased.property_id  || webhookBody.property_id,
        conclusion_id:     deceased.conclusion_id || webhookBody.conclusion_id,
        session_id:        webhookBody.session_id || null,
        cascade_depth:        currentDepth + 1,
        parent_share_pct:     deceased.share_pct,
        cascade_parent:       data.root_decedent,
        estate_path_status:   'unknown_check_court_records'
      })
    });

    const sub = typeof resp === 'string' ? JSON.parse(resp) : resp;
    const subLiving = (sub.living_heirs || []).map(h => ({
      ...h,
      share_pct:         parseFloat(((h.share_pct / 100) * deceased.share_pct).toFixed(4)),
      relationship_path: `${h.relationship_path || h.name} → via ${deceased.name}`,
      estate_path:       `${h.estate_path || 'intestate'} → cascade from ${deceased.name}`
    }));

    living_heirs.push(...subLiving);

    if (sub.gaps && sub.gaps.length) {
      gaps.push(...sub.gaps.map(g => `[${deceased.name} cascade] ${g}`));
    }

    deceased_in_chain.push({
      name:              deceased.name,
      relationship_path: `${deceased.relationship} of ${data.root_decedent}`,
      share_pct:         deceased.share_pct,
      share_fraction:    deceased.share_fraction,
      dod:               deceased.dod || null,
      estate_type:       sub.status !== 'error' ? 'intestate' : null,
      cascaded_to:       subLiving.map(h => h.name),
      evidence:          deceased.verification || {}
    });

  } catch (err) {
    gaps.push(`${deceased.name} — cascade error: ${err.message}`);
    deceased_in_chain.push({
      name:              deceased.name,
      relationship_path: `${deceased.relationship} of ${data.root_decedent}`,
      share_pct:         deceased.share_pct,
      share_fraction:    deceased.share_fraction,
      dod:               deceased.dod || null,
      estate_type:       null,
      cascaded_to:       [],
      evidence:          deceased.verification || {}
    });
  }
}

return [{
  json: {
    living_heirs,
    deceased_in_chain,
    gaps,
    credits_used:  data.credits_used  || 0,
    root_decedent: data.root_decedent,
    property_id:   data.property_id,
    conclusion_id: data.conclusion_id
  }
}];
